import{_ as a,c as e,o as m,d as t}from"./plugin-vue_export-helper.bd4ff235.js";const q='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 27-28","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 27-28","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-25T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/27-28.md","lastUpdated":1626206079000}',o={},p=t('<div class="stanza"><a href="#s3.27" id="s3.27" class="num">3.27</a><div class="sans"><p>\u090F\u0935\u0902\u0935\u093F\u0927\u0938\u094D\u092F\u093E\u0938\u094D\u092F\u2014</p><blockquote><p><strong>\u0915\u0925\u093E \u091C\u092A\u0903\u0965\u0968\u096D\u0965</strong></p></blockquote><blockquote><p>\u0905\u0939\u092E\u0947\u0935 \u092A\u0930\u094B \u0939\u0902\u0938\u0903 \u0936\u093F\u0935\u0903 \u092A\u0930\u092E\u0915\u093E\u0930\u0923\u092E\u094D\u0964</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u0928\u093F\u0924\u094D\u092F\u092E\u0947\u0935 \u092A\u0930\u093E\u0939\u0902\u092D\u093E\u0935\u0928\u093E\u092E\u092F\u0924\u094D\u0935\u093E\u0924\u094D\u0964</p><blockquote><p>\u0924\u0938\u094D\u092F \u0926\u0947\u0935\u093E\u0924\u093F\u0926\u0947\u0935\u0938\u094D\u092F \u092A\u0930\u092C\u094B\u0927\u0938\u094D\u0935\u0930\u0942\u092A\u093F\u0923\u0903\u0964<br> \u0935\u093F\u092E\u0930\u094D\u0936\u0903 \u092A\u0930\u092E\u093E \u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u0930\u094D\u0935\u091C\u094D\u091E\u093E \u091C\u094D\u091E\u093E\u0928\u0936\u093E\u0932\u093F\u0928\u0940\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u0915\u093E\u0932\u093F\u0915\u093E\u0915\u094D\u0930\u092E\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u092E\u0939\u093E\u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0924\u094D\u092E\u0915\u093E\u0915\u0943\u0924\u0915\u093E\u0939\u0902\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0930\u0942\u0922\u0938\u094D\u092F \u092F\u0926\u094D\u092F\u0926\u093E\u0932\u093E\u092A\u093E\u0926\u093F \u0924\u0924\u094D\u0924\u0926\u0938\u094D\u092F \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0926\u0947\u0935\u0924\u093E\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0928\u0935\u0930\u0924\u093E\u0935\u0930\u094D\u0924\u0928\u093E\u0924\u094D\u092E\u093E \u091C\u092A\u094B \u091C\u093E\u092F\u0924\u0947\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u092D\u0942\u092F\u094B \u092D\u0942\u092F\u0903 \u092A\u0930\u0947 \u092D\u093E\u0935\u0947 \u092D\u093E\u0935\u0928\u093E \u092D\u093E\u0935\u094D\u092F\u0924\u0947 \u0939\u093F \u092F\u093E\u0964<br> \u091C\u092A\u0903 \u0938\u094B\u093D\u0924\u094D\u0930 \u0938\u094D\u0935\u092F\u0902 \u0928\u093E\u0926\u094B \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0924\u094D\u092E\u093E \u091C\u092A\u094D\u092F \u0908\u0926\u0943\u0936\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0925\u093E</p><blockquote><p>\u0938\u0915\u093E\u0930\u0947\u0923 \u092C\u0939\u093F\u0930\u094D\u092F\u093E\u0924\u093F \u0939\u0915\u093E\u0930\u0947\u0923 \u0935\u093F\u0936\u0947\u0924\u094D\u092A\u0941\u0928\u0903\u0964<br> \u0939\u0902\u0938\u0939\u0902\u0938\u0947\u0924\u094D\u092F\u092E\u0941\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u0902 \u091C\u0940\u0935\u094B \u091C\u092A\u0924\u093F \u0928\u093F\u0924\u094D\u092F\u0936\u0903\u0965<br> \u0937\u091F\u094D\u0936\u0924\u093E\u0928\u093F \u0926\u093F\u0935\u093E\u0930\u093E\u0924\u094D\u0930\u094C \u0938\u0939\u0938\u094D\u0930\u093E\u0923\u094D\u092F\u0947\u0915\u0935\u093F\u0902\u0936\u0924\u093F\u0903\u0964<br> \u091C\u092A\u094B \u0926\u0947\u0935\u094D\u092F\u093E \u0935\u093F\u0928\u093F\u0930\u094D\u0926\u093F\u0937\u094D\u091F\u0903 \u0938\u0941\u0932\u092D\u094B \u0926\u0941\u0930\u094D\u0932\u092D\u094B \u091C\u0921\u0948\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0968\u096D\u0965</p></div><hr><div class="trans"><p>Eva\u1E41vidhasy\u0101sya\u2014</p><blockquote><p><strong>Kath\u0101 japa\u1E25||27||</strong></p></blockquote><blockquote><p>Ahameva paro ha\u1E41sa\u1E25 \u015Biva\u1E25 paramak\u0101ra\u1E47am|</p></blockquote><p>iti \u015Br\u012Bsvacchandanir\u016Bpitan\u012Bty\u0101 nityameva par\u0101ha\u1E41bh\u0101van\u0101mayatv\u0101t|</p><blockquote><p>Tasya dev\u0101tidevasya parabodhasvar\u016Bpi\u1E47a\u1E25|<br> Vimar\u015Ba\u1E25 param\u0101 \u015Bakti\u1E25 sarvaj\xF1\u0101 j\xF1\u0101na\u015B\u0101lin\u012B||</p></blockquote><p>iti \u015Br\u012Bk\u0101lik\u0101kramanir\u016Bpitan\u012Bty\u0101 mah\u0101mantr\u0101tmak\u0101k\u1E5Btak\u0101ha\u1E41vimar\u015B\u0101r\u016B\u1E0Dhasya yadyad\u0101l\u0101p\u0101di tattadasya sv\u0101tmadevat\u0101vimar\u015B\u0101navarat\u0101vartan\u0101tm\u0101 japo j\u0101yate| Yadukta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Bh\u016Byo bh\u016Bya\u1E25 pare bh\u0101ve bh\u0101van\u0101 bh\u0101vyate hi y\u0101|<br> Japa\u1E25 so&#39;tra svaya\u1E41 n\u0101do mantr\u0101tm\u0101 japya \u012Bd\u1E5B\u015Ba\u1E25||</p></blockquote><p>iti| Tath\u0101</p><blockquote><p>Sak\u0101re\u1E47a bahiry\u0101ti hak\u0101re\u1E47a vi\u015Betpuna\u1E25|<br> Ha\u1E41saha\u1E41setyamu\u1E41 mantra\u1E41 j\u012Bvo japati nitya\u015Ba\u1E25||<br> \u1E62a\u1E6D\u015Bat\u0101ni div\u0101r\u0101trau sahasr\u0101\u1E47yekavi\u1E41\u015Bati\u1E25|<br> Japo devy\u0101 vinirdi\u1E63\u1E6Da\u1E25 sulabho durlabho ja\u1E0Dai\u1E25||</p></blockquote><p>iti||27||</p></div><hr><p>\u0427\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u0442\u0430\u043A\u043E\u0433\u043E [Yog\u012B] <em>(eva\u1E41vidhasya asya)</em>\u2014</p><blockquote><p><strong>[\u0415\u0433\u043E] \u0440\u0435\u0447\u044C <em>(kath\u0101)</em> \u2014 \u044D\u0442\u043E \u043D\u0430\u0447\u0438\u0442\u044B\u0432\u0430\u043D\u0438\u0435 [\u041C\u0430\u043D\u0442\u0440\u044B \u0438\u043B\u0438 \u043C\u043E\u043B\u0438\u0442\u0432\u044B] <em>(japa\u1E25)</em>||27||</strong></p></blockquote><blockquote><p>&quot;\u041D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(eva)</em>, \u042F <em>(aham)</em> [\u0435\u0441\u0442\u044C] \u0412\u044B\u0441\u0448\u0430\u044F <em>(para\u1E25)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u044C, \u0438\u043B\u0438 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(ha\u1E41sa\u1E25)</em>, [\u042F \u0435\u0441\u0442\u044C] \u015Aiva <em>(\u015Biva\u1E25)</em>, \u0412\u044B\u0441\u0448\u0430\u044F <em>(parama)</em> \u041F\u0440\u0438\u0447\u0438\u043D\u0430 <em>(k\u0101ra\u1E47am... iti)</em>&quot;||<br> [\u0421\u043C. \u0437\u0430\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u0443\u044E \u0447\u0430\u0441\u0442\u044C IV, 399 \u0432 Svacchandatantra]</p></blockquote><p>\u043A\u0430\u043A \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043E <em>(nir\u016Bpita-n\u012Bty\u0101)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C <em>(\u015Br\u012B)</em> Svacchandatantra <em>(svacchanda)</em>, [\u0435\u0433\u043E \u0440\u0435\u0447\u044C \u2014 \u044D\u0442\u043E \u043D\u0430\u0447\u0438\u0442\u044B\u0432\u0430\u043D\u0438\u0435 \u041C\u0430\u043D\u0442\u0440\u044B \u0438\u043B\u0438 \u043C\u043E\u043B\u0438\u0442\u0432\u044B], \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [\u0442\u0430\u043A\u043E\u0439 Yog\u012B] \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043F\u043E\u043B\u043E\u043D <em>(nityam eva... mayatv\u0101t)</em> \u0432\u044B\u0441\u0448\u0435\u0433\u043E <em>(para)</em> \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F <em>(bh\u0101van\u0101)</em> \u042F-[\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(aham)</em>|</p><blockquote><p>&quot;[\u042F]-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(vimar\u015Ba\u1E25)</em> [\u0438\u043B\u0438] \u0412\u044B\u0441\u0448\u0430\u044F <em>(param\u0101)</em> \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u0432\u0435\u0434\u0430\u044E\u0449\u0435\u0439 <em>(sarvaj\xF1\u0101)</em>, \u0442.\u0435. \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0439 <em>(\u015B\u0101lin\u012B)</em> \u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(j\xF1\u0101na)</em>, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u0422\u043E\u043C\u0443 <em>(tasya)</em>, \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0435\u043B\u0438\u0447\u0430\u0439\u0448\u0438\u043C \u0411\u043E\u0433\u043E\u043C <em>(atidevasya)</em> \u0441\u0440\u0435\u0434\u0438 \u0431\u043E\u0433\u043E\u0432 <em>(deva)</em>, [\u0438] \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpi\u1E47a\u1E25)</em> \u0435\u0441\u0442\u044C \u0412\u044B\u0441\u0448\u0435\u0435 <em>(para)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(bodha... iti)</em>&quot;||</p></blockquote><p>\u041A\u0430\u043A \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043E <em>(nir\u016Bpita-n\u012Bty\u0101)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C <em>(\u015Br\u012B)</em> K\u0101lik\u0101krama <em>(k\u0101lik\u0101krama)</em>, \u043B\u044E\u0431\u043E\u0439 <em>(yad yad)</em> \u0440\u0430\u0437\u0433\u043E\u0432\u043E\u0440 <em>(\u0101l\u0101pa)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>[Yog\u012B], \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0435\u0433\u043E <em>(\u0101r\u016B\u1E0Dhasya)</em> \u043D\u0435\u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0433\u043E <em>(ak\u1E5Btaka)</em> \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(aha\u1E41-vimar\u015Ba)</em>, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0441\u043E\u0431\u043E\u0439 <em>(\u0101tma)</em> \u0432\u0435\u043B\u0438\u043A\u0443\u044E <em>(mah\u0101)</em> \u041C\u0430\u043D\u0442\u0440\u0443 <em>(mantra)</em>, \u0432\u0441\u0435 \u044D\u0442\u043E <em>(tad tad)</em> \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 <em>(j\u0101yate)</em> \u0435\u0433\u043E <em>(asya)</em> japa --\u043D\u0430\u0447\u0438\u0442\u044B\u0432\u0430\u043D\u0438\u0435 \u041C\u0430\u043D\u0442\u0440\u044B \u0438\u043B\u0438 \u043C\u043E\u043B\u0438\u0442\u0432\u044B-- <em>(japa\u1E25)</em>, \u0441\u0443\u0442\u044C \u043A\u043E\u0442\u043E\u0440\u043E\u0439 <em>(\u0101tm\u0101)</em> \u2014 \u043D\u0435\u043F\u0440\u0435\u0441\u0442\u0430\u043D\u043D\u043E\u0435 <em>(avarata)</em> \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u0435 <em>(\u0101vartana)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(vimar\u015Ba)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430 [\u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u041C\u0430\u043D\u0442\u0440\u044B] <em>(devat\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E <em>(\u0101tma)</em><sup>1</sup>|</p><p>\u042D\u0442\u043E [\u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0443\u0447\u0435\u043D\u0438\u0435] <em>(yad)</em> \u0431\u044B\u043B\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Vij\xF1\u0101nabhairavatantra <em>(\u015Br\u012B-vij\xF1\u0101nabhairave)</em>:</p><blockquote><p>&quot;\u042D\u0442\u043E <em>(y\u0101)</em> \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 <em>(bh\u0101van\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F <em>(bh\u0101vyate hi)</em> \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430 <em>(bh\u016Byas bh\u016Byas)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(pare)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101ve)</em>, [\u0435\u0441\u0442\u044C] japa <em>(japa\u1E25 sa\u1E25)</em> \u0432 \u044D\u0442\u043E\u043C [\u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435] <em>(atra)</em>. \u0422\u0430\u043A\u043E\u0439 <em>(\u012Bd\u1E5B\u015Ba\u1E25)</em> \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u044B\u0439 --\u0442.\u0435. \u0437\u0432\u0443\u0447\u0430\u0449\u0438\u0439 \u0441\u0430\u043C \u043F\u043E \u0441\u0435\u0431\u0435-- <em>(svayam)</em> \u0437\u0432\u0443\u043A <em>(n\u0101da\u1E25)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(\u0101tm\u0101)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u041C\u0430\u043D\u0442\u0440\u0430 <em>(mantra)</em>, [\u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442] \u043E\u0431\u044A\u0435\u043A\u0442 japa <em>(japya\u1E25... iti)</em> --\u0442.\u0435. \u0442\u0430\u043A\u043E\u0439 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u044B\u0439 \u0437\u0432\u0443\u043A \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430--<sup>2</sup>&quot;||</p></blockquote><p>\u0422\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em>, [\u044D\u0442\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E \u0432 \u0442\u043E\u043C \u0436\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u0438]:</p><blockquote><p>&quot;[\u0422\u043E\u043D\u043A\u0430\u044F \u043C\u0430\u043D\u0442\u0440\u0430] &#39;Ha\u1E41sa, Ha\u1E41sa&#39; <em>(ha\u1E41saha\u1E41sa iti)</em> \u0432\u044B\u0445\u043E\u0434\u0438\u0442 <em>(bahis y\u0101ti)</em> \u0441\u043E \u0437\u0432\u0443\u043A\u043E\u043C <em>(k\u0101re\u1E47a)</em> &#39;Sa&#39; <em>(sa)</em> \u0438 \u0432\u0445\u043E\u0434\u0438\u0442 <em>(vi\u015Bet)</em> \u0441\u043D\u043E\u0432\u0430 <em>(punar)</em> \u0441\u043E \u0437\u0432\u0443\u043A\u043E\u043C <em>(k\u0101re\u1E47a)</em> &#39;Ha&#39; <em>(ha)</em>. [\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435], \u0436\u0438\u0432\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 <em>(j\u012Bva\u1E25)</em> \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(nitya\u015Ba\u1E25)</em> \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0442 <em>(japati)</em> \u044D\u0442\u0443 <em>(amum)</em> \u043C\u0430\u043D\u0442\u0440\u0443 <em>(mantram)</em>. \u0414\u0435\u043D\u044C \u0438 \u043D\u043E\u0447\u044C <em>(div\u0101r\u0101trau)</em> [\u044D\u0442\u0438 \u0436\u0438\u0432\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u043D\u0430\u0447\u0438\u0442\u044B\u0432\u0430\u044E\u0442 \u0435\u0435] 21,600 [\u0440\u0430\u0437] <em>(\u1E63a\u1E6D\u015Bat\u0101ni... sahasr\u0101\u1E47i ekavi\u1E41\u015Bati\u1E25)</em>. \u041D\u0430\u0447\u0438\u0442\u044B\u0432\u0430\u043D\u0438\u0435 <em>(japa\u1E25)</em> \u0411\u043E\u0433\u0438\u043D\u0438 <em>(devy\u0101\u1E25)</em> \u0431\u044B\u043B\u043E \u0443\u043A\u0430\u0437\u0430\u043D\u043E <em>(vinirdi\u1E63\u1E6Da\u1E25)</em>, \u043A\u0430\u043A \u043B\u0435\u0433\u043A\u043E\u0435 <em>(sulabha\u1E25)</em> [\u0434\u043B\u044F \u043C\u0443\u0434\u0440\u043E\u0433\u043E, \u043D\u043E] \u0442\u0440\u0443\u0434\u043D\u043E\u0435 <em>(durlabha\u1E25)</em> \u0434\u043B\u044F \u0433\u043B\u0443\u043F\u043E\u0433\u043E <em>(ja\u1E0Dai\u1E25... iti)</em>&quot;||</p></blockquote><p>||27||</p><hr><ol><li><p>\u0411\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u041C\u0430\u043D\u0442\u0440\u044B \u2014 \u044D\u0442\u043E \u015Aiva (\u0432\u0430\u0448\u0430 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0421\u0430\u043C\u043E\u0441\u0442\u044C). \u042D\u0442\u043E\u0442 \u015Aiva \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0438\u043C\u044B\u043C \u043E\u0442 \u0421\u0432\u043E\u0435\u0439 \u015Aakti, \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0438\u043B\u044B, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u043A\u0430\u043A &quot;\u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435&quot;. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0432\u0435\u043B\u0438\u043A\u0430\u044F \u041C\u0430\u043D\u0442\u0440\u0430 \u043F\u043E\u0432\u0442\u043E\u0440\u044F\u0435\u0442\u0441\u044F \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0438 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432 \u0444\u043E\u0440\u043C\u0435 &quot;Aham&quot;, \u0438\u043B\u0438 &quot;\u042F&quot;. \u0411\u0435\u0437 &quot;\u042F&quot; \u043D\u0438\u0447\u0442\u043E \u043D\u0435 \u043C\u043E\u0433\u043B\u043E \u0431\u044B \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u044C\u0441\u044F. \u0418\u0442\u0430\u043A, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E\u0442 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 Yog\u012B \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 &quot;Aham&quot;, \u0432\u0441\u0435 \u0435\u0433\u043E \u0440\u0430\u0437\u0433\u043E\u0432\u043E\u0440\u044B \u043F\u043E\u0434\u043E\u0431\u043D\u044B \u0435\u0433\u043E japa.</p></li><li><p>\u041A\u0430\u043A \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u043B\u043E\u0441\u044C \u0432 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u043C \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0438, japa \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u044D\u0442\u043E\u0433\u043E \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0430\u0436\u0435 \u043D\u0435 \u043D\u0430\u0447\u0438\u0442\u044B\u0432\u0430\u043D\u0438\u0435\u043C \u043C\u0430\u043D\u0442\u0440\u044B, \u043A\u0430\u043A \u044D\u0442\u043E \u043E\u0431\u044B\u0447\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F, \u0430 \u0442\u043E\u043B\u044C\u043A\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435\u043C \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F (\u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u015Aiva). Aham, \u0438\u043B\u0438 \u042F \u2014 \u044D\u0442\u043E \u0437\u0432\u0443\u043A, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u0437\u0432\u0443\u0447\u0430\u0442\u044C \u0441\u0430\u043C \u043F\u043E \u0441\u0435\u0431\u0435 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 Aham, \u0438\u043B\u0438 \u042F (\u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F) \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u0435\u043C, \u0447\u0442\u043E \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 japa \u044D\u0442\u043E\u0433\u043E \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B. \u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u043D\u044F\u0442\u043D\u043E, \u0442\u0430\u043A \u0432\u0435\u0434\u044C?</p></li></ol></div><div class="stanza"><a href="#s3.28" id="s3.28" class="num">3.28</a><div class="sans"><p>\u0908\u0926\u0943\u0917\u094D\u091C\u092A\u0935\u094D\u0930\u0924\u0935\u0924\u094B\u093D\u0938\u094D\u092F \u091A\u0930\u094D\u092F\u093E\u092E\u093E\u0939\u2014</p><blockquote><p><strong>\u0926\u093E\u0928\u092E\u093E\u0924\u094D\u092E\u091C\u094D\u091E\u093E\u0928\u092E\u094D\u0965\u0968\u096E\u0965</strong></p></blockquote><p>\u092A\u094D\u0930\u094B\u0915\u094D\u0924\u091A\u0948\u0924\u0928\u094D\u092F\u0930\u0942\u092A\u0938\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u094B \u092F\u091C\u094D\u091C\u094D\u091E\u093E\u0928\u0902 \u0938\u093E\u0915\u094D\u0937\u093E\u0924\u094D\u0915\u093E\u0930\u0938\u094D\u0924\u0926\u0938\u094D\u092F \u0926\u093E\u0928\u0902 \u0926\u0940\u092F\u0924\u0947 \u092A\u0930\u093F\u092A\u0942\u0930\u094D\u0923\u0902 \u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u0926\u0940\u092F\u0924\u0947 \u0916\u0923\u094D\u0921\u094D\u092F\u0924\u0947 \u0935\u093F\u0936\u094D\u0935\u092D\u0947\u0926\u094B \u0926\u093E\u092F\u0924\u0947 \u0936\u094B\u0927\u094D\u092F\u0924\u0947 \u092E\u093E\u092F\u093E\u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u0926\u0940\u092F\u0924\u0947 \u0930\u0915\u094D\u0937\u094D\u092F\u0924\u0947 \u0932\u092C\u094D\u0927\u0903 \u0936\u093F\u0935\u093E\u0924\u094D\u092E\u093E \u0938\u094D\u0935\u092D\u093E\u0935\u0936\u094D\u091A\u093E\u0928\u0947\u0928\u0947\u0924\u093F \u0915\u0943\u0924\u094D\u0935\u093E\u0964</p><p>\u0905\u0925 \u091A \u0926\u0940\u092F\u0924 \u0907\u0924\u093F \u0926\u093E\u0928\u092E\u093E\u0924\u094D\u092E\u091C\u094D\u091E\u093E\u0928\u092E\u0947\u0935\u093E\u0928\u0947\u0928\u093E\u0928\u094D\u0924\u0947\u0935\u093E\u0938\u093F\u092D\u094D\u092F\u094B \u0926\u0940\u092F\u0924\u0947\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u092E\u094D</p><blockquote><p>\u0926\u0930\u094D\u0936\u0928\u093E\u0924\u094D\u0938\u094D\u092A\u0930\u094D\u0936\u0928\u093E\u0926\u094D\u0935\u093E\u092A\u093F \u0935\u093F\u0924\u0924\u093E\u0926\u094D\u092D\u0935\u0938\u093E\u0917\u0930\u093E\u0924\u094D\u0964<br> \u0924\u093E\u0930\u092F\u093F\u0937\u094D\u092F\u0928\u094D\u0924\u093F \u092F\u094B\u0917\u0940\u0928\u094D\u0926\u094D\u0930\u093E\u0903 \u0915\u0941\u0932\u093E\u091A\u093E\u0930\u092A\u094D\u0930\u0924\u093F\u0937\u094D\u0920\u093F\u0924\u093E\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0968\u096E\u0965</p></div><hr><div class="trans"><p>\u012Ad\u1E5Bgjapavratavato&#39;sya cary\u0101m\u0101ha\u2014</p><blockquote><p><strong>D\u0101nam\u0101tmaj\xF1\u0101nam||28||</strong></p></blockquote><p>Proktacaitanyar\u016Bpasy\u0101tmano yajj\xF1\u0101na\u1E41 s\u0101k\u1E63\u0101tk\u0101rastadasya d\u0101na\u1E41 d\u012Byate parip\u016Br\u1E47a\u1E41 svar\u016Bpa\u1E41 d\u012Byate kha\u1E47\u1E0Dyate vi\u015Bvabhedo d\u0101yate \u015Bodhyate m\u0101y\u0101svar\u016Bpa\u1E41 d\u012Byate rak\u1E63yate labdha\u1E25 \u015Biv\u0101tm\u0101 svabh\u0101va\u015Bc\u0101neneti k\u1E5Btv\u0101|</p><p>Atha ca d\u012Byata iti d\u0101nam\u0101tmaj\xF1\u0101namev\u0101nen\u0101ntev\u0101sibhyo d\u012Byate| Taduktam</p><blockquote><p>Dar\u015Ban\u0101tspar\u015Ban\u0101dv\u0101pi vitat\u0101dbhavas\u0101gar\u0101t|<br> T\u0101rayi\u1E63yanti yog\u012Bndr\u0101\u1E25 kul\u0101c\u0101raprati\u1E63\u1E6Dhit\u0101\u1E25||</p></blockquote><p>iti||28||</p></div><hr><p>[\u0427\u0435\u0440\u0435\u0437 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C, \u015Aiva] \u0433\u043E\u0432\u043E\u0440\u0438\u043B <em>(\u0101ha)</em> \u043E\u0431 \u043E\u0431\u0440\u0430\u0437\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439, \u0438\u043B\u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0438 <em>(cary\u0101m)</em> \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u0435\u0442 \u0442\u0430\u043A\u0438\u0435 japa \u0438 vrata --\u0421\u043C\u043E\u0442\u0440\u0438\u0442\u0435 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0435 \u0434\u0432\u0430 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430-- <em>(\u012Bd\u1E5Bk-japavratavata\u1E25)</em>\u2014</p><blockquote><p><strong>\u0417\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tma)</em> \u2014 [\u0435\u0433\u043E] \u0434\u0430\u0440 <em>(d\u0101nam)</em> [\u0432\u0441\u0435\u043C \u043D\u0430\u043C]||28||</strong></p></blockquote><p>\u042D\u0442\u043E <em>(yad)</em> \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u0438 (\u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F) <em>(\u0101tmana\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(r\u016Bpasya)</em> \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u043C \u0440\u0430\u043D\u0435\u0435 --\u0421\u043C. I, 1-- <em>(prokta)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u044B\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(caitanya)</em>, \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438 [\u044D\u0442\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438] <em>(s\u0101k\u1E63\u0101tk\u0101ra\u1E25)</em>. \u0422\u0430\u043A\u043E\u0435 [\u0437\u043D\u0430\u043D\u0438\u0435] <em>(tad)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0435\u0433\u043E <em>(asya)</em> \u0434\u0430\u0440\u043E\u043C <em>(d\u0101nam)</em>. \u0418 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044F \u0432\u043E \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 [\u043A\u043E\u0440\u043D\u0438, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0442\u0435\u0440\u043C\u0438\u043D d\u0101na, \u0438\u043B\u0438 \u0434\u0430\u0440 \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u0435\u043B] <em>(iti k\u1E5Btv\u0101)</em>: &quot;\u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u0430\u044F <em>(parip\u016Br\u1E47a)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpam)</em> \u0434\u0430\u043D\u0430 [\u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0434\u0430\u0440\u0430] <em>(d\u012Byate)</em>. [\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 \u0434\u0430\u0440\u0443,] \u0440\u0430\u0437\u043D\u0438\u0446\u0430 <em>(bheda\u1E25)</em> [\u043C\u0435\u0436\u0434\u0443 \u015Aiva \u0438] \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em> \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0430 <em>(d\u012Byate)</em> [\u0438\u043B\u0438] \u0440\u0430\u0441\u0441\u0435\u0447\u0435\u043D\u0430 <em>(kha\u1E47\u1E0Dyate)</em> --\u0442.\u0435. \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F--; \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(sva-r\u016Bpam)</em> M\u0101y\u0101 <em>(m\u0101y\u0101)</em> \u043E\u0447\u0438\u0449\u0435\u043D\u0430 <em>(d\u0101yate)</em> [\u0438\u043B\u0438] \u043E\u0447\u0438\u0449\u0430\u0435\u0442\u0441\u044F <em>(\u015Bodhyate)</em>, \u0438 <em>(ca)</em> \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(sva-bh\u0101va\u1E25)</em> \u2014\u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tm\u0101)</em> \u2014 \u015Aiva <em>(\u015Biva)</em>\u2014 \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0431\u044B\u043B\u043E \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E <em>(labdha\u1E25)</em> \u044D\u0442\u0438\u043C [\u0432\u0435\u043B\u0438\u043A\u0438\u043C Yog\u012B] <em>(anena)</em>, \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442\u0441\u044F <em>(d\u012Byate)</em> [\u0438\u043B\u0438] \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442\u0441\u044F <em>(rak\u1E63yate)</em><sup>1</sup>&quot;|</p><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 --\u0442.\u0435 \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u0442\u0435\u0440\u043C\u0438\u043D\u0430 d\u0101na, \u0438\u043B\u0438 \u0434\u0430\u0440\u0430 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C \u043A\u043E\u0440\u043D\u044F\u043C-- <em>(atha ca)</em>, \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam eva)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tma)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0434\u0430\u0440\u043E\u043C <em>(d\u0101nam)</em>, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u043E \u0434\u0430\u0435\u0442\u0441\u044F <em>(d\u012Byate iti)</em> [\u0438\u043B\u0438] \u043F\u0435\u0440\u0435\u0434\u0430\u0435\u0442\u0441\u044F <em>(d\u012Byate)</em> \u0438\u043C <em>(anena)</em> \u0443\u0447\u0435\u043D\u0438\u043A\u0430\u043C, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0436\u0438\u0432\u0443\u0442 \u043F\u043E\u0431\u043B\u0438\u0437\u043E\u0441\u0442\u0438 \u0438\u043B\u0438 \u0432 \u0435\u0433\u043E \u0434\u043E\u043C\u0435 <em>(antev\u0101sibhya\u1E25)</em><sup>2</sup> --\u0442\u043E\u0433\u0434\u0430 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u0442\u043E, \u0447\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043E\u0442 \u043A\u043E\u0440\u043D\u044F &quot;d\u0101&quot;, \u0438\u043B\u0438 &quot;\u0434\u0430\u0432\u0430\u0442\u044C&quot;--|</p><p>\u042D\u0442\u043E [\u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0443\u0447\u0435\u043D\u0438\u0435] <em>(tad)</em> \u0431\u044B\u043B\u043E [\u044F\u0441\u043D\u043E] \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E <em>(uktam)</em> [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0439 \u0441\u0442\u0440\u043E\u0444\u043E\u0439]:</p><blockquote><p>&quot;\u041B\u0443\u0447\u0448\u0438\u0435 Yog\u012B-s <em>(yogi-indr\u0101\u1E25)</em>, \u043F\u0440\u043E\u0447\u043D\u043E \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0435 <em>(prati\u1E63\u1E6Dhit\u0101\u1E25)</em> \u0432 Kul\u0101c\u0101ra --\u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 \u015Aiva (\u0413\u043E\u0441\u043F\u043E\u0434\u0430), \u015Aakti (\u0415\u0433\u043E \u0421\u0438\u043B\u044B) \u0438 nara (\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0443\u0448\u0438)-- <em>(kula-\u0101c\u0101ra)</em>, \u0431\u0443\u0434\u0443\u0442 \u0441\u043F\u0430\u0441\u0430\u0442\u044C <em>(t\u0101rayi\u1E63yanti)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432] \u0438\u0437 \u043E\u0431\u0448\u0438\u0440\u043D\u043E\u0433\u043E <em>(vitat\u0101t)</em> \u043E\u043A\u0435\u0430\u043D\u0430 \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(bhava-s\u0101gar\u0101t)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0438\u0445 \u043F\u0440\u043E\u0441\u0442\u043E\u0433\u043E] \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044F <em>(dar\u015Ban\u0101t)</em> \u0438\u043B\u0438 <em>(v\u0101 api)</em> \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(spar\u015Ban\u0101t... iti)</em><sup>3</sup>&quot;||</p></blockquote><p>||28||</p><hr><ol><li><p>\u041A\u0440\u0430\u0442\u043A\u043E \u0434\u043B\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432, \u043A\u043E\u0440\u043D\u0438 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0435: d\u0101 (\u0434\u0430\u0432\u0430\u0442\u044C, \u0434\u043E\u043C, \u0438\u043B\u0438 \u043A\u043B\u0430\u0441\u0441 3), do (\u043E\u0442\u0440\u0435\u0437\u0430\u0442\u044C, \u0434\u043E\u043C \u0438\u043B\u0438 \u043A\u043B\u0430\u0441\u0441 2), dai (\u043E\u0447\u0438\u0449\u0430\u0442\u044C, \u0434\u043E\u043C \u0438\u043B\u0438 \u043A\u043B\u0430\u0441\u0441 1) \u0438 d\u012B (\u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0442\u044C, \u0434\u043E\u043C \u0438\u043B\u0438 \u043A\u043B\u0430\u0441\u0441 2).</p></li><li><p>\u0421\u043B\u043E\u0432\u043E &quot;antev\u0101sibhya\u1E25&quot; \u2014 \u0414\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u0434\u0435\u0436 (\u043C\u043D. \u0447. \u043C\u0443\u0436\u0441\u043A\u043E\u0433\u043E \u0440\u043E\u0434\u0430) \u043E\u0442 &quot;antev\u0101sin&quot;. \u0418\u043C\u0435\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u0434\u0435\u0436 (\u0435\u0434.\u0447. \u043C\u0443\u0436\u0441\u043A\u043E\u0433\u043E \u0440\u043E\u0434\u0430) \u2014 &quot;antev\u0101s\u012B&quot;, \u0438\u043B\u0438 &quot;\u0443\u0447\u0435\u043D\u0438\u043A, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u0439\u0441\u044F \u043F\u043E\u0431\u043B\u0438\u0437\u043E\u0441\u0442\u0438 \u0438\u043B\u0438 \u0432 \u0434\u043E\u043C\u0435 \u0441\u0432\u043E\u0435\u0433\u043E \u0443\u0447\u0438\u0442\u0435\u043B\u044F&quot;. \u042D\u0442\u043E \u043E\u0447\u0435\u043D\u044C \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u043E, \u0447\u0442\u043E \u043D\u0430\u043F\u0438\u0441\u0430\u043B \u043C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043C\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u043E\u0436\u0438\u0434\u0430\u0442\u044C &quot;\u015Bi\u1E63yebhya\u1E25&quot; \u0438\u043B\u0438 &quot;\u015Bi\u1E63ya-s \u0438\u043B\u0438 \u0443\u0447\u0435\u043D\u0438\u043A\u0430\u043C&quot;, \u0432 \u043E\u0431\u0449\u0435\u043C, \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E \u043E\u0442 \u0442\u043E\u0433\u043E, \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u043B\u0438 \u043E\u043D\u0438 \u0440\u044F\u0434\u043E\u043C \u0438\u043B\u0438 \u0434\u0430\u043B\u0435\u043A\u043E \u043E\u0442 \u0441\u0432\u043E\u0435\u0433\u043E \u0443\u0447\u0438\u0442\u0435\u043B\u044F. \u042F \u043C\u043E\u0433 \u0431\u044B \u0437\u0430\u0431\u044B\u0442\u044C \u043E\u0431 \u044D\u0442\u043E\u043C \u0438 \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 &quot;\u0443\u0447\u0435\u043D\u0438\u043A\u0430\u043C&quot;, \u043D\u043E \u044D\u0442\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u043D\u0435 \u0442\u043E\u0447\u043D\u043E. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u0439 \u0437\u0430\u0442\u0435\u043C \u0441\u0442\u0440\u043E\u0444\u0435, \u043C\u0443\u0434\u0440\u0435\u0446 \u043F\u0440\u0438\u0434\u0430\u0435\u0442 \u0431\u043E\u043B\u044C\u0448\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0411\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u0438\u044E, \u043F\u0435\u0440\u0435\u0434\u0430\u0432\u0430\u0435\u043C\u043E\u043C\u0443 \u0447\u0435\u0440\u0435\u0437 \u0437\u0440\u0435\u043D\u0438\u0435 \u0438\u043B\u0438 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0438\u043C\u0435\u0442\u044C \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432 \u0432 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u0445 \u0434\u043E\u0441\u044F\u0433\u0430\u0435\u043C\u043E\u0441\u0442\u0438, \u0441 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F.</p></li><li><p>\u0417\u0434\u0435\u0441\u044C \u0441\u0442\u0440\u043E\u0444\u0430 \u0443\u0447\u0438\u0442, \u0447\u0442\u043E \u0433\u043B\u0430\u0432\u043D\u044B\u0435 \u0441\u0440\u0435\u0434\u0438 Yog\u012B-s \u0431\u0443\u0434\u0443\u0442 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0430\u0442\u044C \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 \u0441\u0432\u043E\u0438\u043C \u043F\u0440\u043E\u0441\u0442\u044B\u043C \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435\u043C (\u0442.\u0435. \u0432\u0437\u0433\u043B\u044F\u0434\u043E\u043C), \u0438 \u0442\u0430\u043A\u0436\u0435 \u0447\u0435\u0440\u0435\u0437 \u0438\u0445 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435. \u0414\u0440\u0443\u0433\u043E\u0435 \u0438\u043C\u044F &quot;\u0437\u043D\u0430\u043D\u0438\u044F \u043E \u0412\u044B\u0441\u0448\u0435\u043C \u042F&quot; \u2014 &quot;\u041C\u0438\u043B\u043E\u0441\u0442\u044C&quot;, \u0442.\u0435. &quot;\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u041C\u0438\u043B\u043E\u0441\u0442\u044C&quot;, \u0438\u043B\u0438 &quot;anugraha&quot;. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043C\u043E\u0435\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438, \u041C\u0438\u043B\u043E\u0441\u0442\u044C \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C &quot;\u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E&quot; \u0434\u0430\u0440\u043E\u0432\u0430\u043D\u0430 \u0443\u0447\u0435\u043D\u0438\u043A\u0430\u043C \u0447\u0435\u0440\u0435\u0437 \u043C\u0430\u043D\u0442\u0440\u0443, \u0438\u043B\u0438 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u043E\u0441\u0442\u043E\u0439 sa\u1E45kalpa, \u0438\u043B\u0438 \u0432\u043E\u043B\u0435\u0432\u044B\u043C \u0430\u043A\u0442\u043E\u043C, \u0442.\u0435. \u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E. \u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u044D\u0442\u0438 \u0434\u0432\u0430 \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043C\u0435\u0442\u043E\u0434\u0430 \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442\u0441\u044F \u0441 \u0442\u0435\u043C\u0438 \u0443\u0447\u0435\u043D\u0438\u043A\u0430\u043C\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F antev\u0101s\u012B-s, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043A\u0442\u043E \u043D\u0435 \u0436\u0438\u0432\u0435\u0442 \u043F\u043E\u0431\u043B\u0438\u0437\u043E\u0441\u0442\u0438 \u0438\u043B\u0438 \u0432 \u0434\u043E\u043C\u0435 \u0438\u0445 \u0433\u0443\u0440\u0443 (\u043A\u0430\u043A \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0432 \u043C\u043E\u0435\u043C \u0441\u043B\u0443\u0447\u0430\u0435!). \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 K\u1E63emar\u0101ja \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E antev\u0101s\u012B-s \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u0437 \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043C\u0435\u0442\u043E\u0434\u044B \u0438\u043D\u0438\u0446\u0438\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432 \u0447\u0435\u0440\u0435\u0437 \u0432\u0437\u0433\u043B\u044F\u0434 (d\u1E5Bk) \u0438 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435 (spar\u015Ba).</p></li></ol></div>',2),i=[p];function r(s,u,n,v,d,h){return m(),e("div",null,i)}var y=a(o,[["render",r]]);export{q as __pageData,y as default};
